     1→import { Button } from "@/components/ui/button";
     2→import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
     3→import { cn } from "@/lib/utils";
     4→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
     5→import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
     6→import { SmartInput, SmartTextarea } from "@/components/ui/smart-input";
     7→import { FormProgress } from "@/components/ui/form-progress";
     8→import { TimePicker } from "@/components/ui/datetime-picker";
     9→import { Calendar } from "@/components/ui/calendar";
    10→import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
    11→import { FloatingPathsBackground } from "@/components/ui/floating-paths-bg";
    12→import { FlickeringGrid } from "@/components/ui/flickering-grid";
    13→import { format, add } from "date-fns";
    14→import { ar as arLocale } from "date-fns/locale";
    15→import { Calendar as CalendarIcon, ArrowLeft, Copy, Check, Mail, ExternalLink, Sparkles, Info, ChevronDown, ChevronUp, Video, Zap } from "lucide-react";
    16→import { useI18n } from "@/lib/i18n";
    17→import logoPath from "@assets/Screenshot_2025-12-11_at_10.30.18_AM-removebg-preview_1765438254196.png";
    18→
    19→import { useForm } from "react-hook-form";
    20→import { zodResolver } from "@hookform/resolvers/zod";
    21→import { useMutation, useQueryClient, useQuery } from "@tanstack/react-query";
    22→import { z } from "zod";
    23→import { apiRequest } from "@/lib/queryClient";
    24→import { useToast } from "@/hooks/use-toast";
    25→import { ToastAction } from "@/components/ui/toast";
    26→import { useAuthStore } from "@/lib/auth";
    27→import { useState, useEffect } from "react";
    28→import VoiceRecorder from "@/components/voice-recorder";
    29→import { useLocation } from "wouter";
    30→import type { Tender } from "@shared/schema";
    31→import { useAutosave, DraftStorage } from "@/lib/autosave";
    32→import { calculateFormProgress, getConstraints } from "@/lib/form-validation";
    33→import { useFormKeyboardShortcuts } from "@/hooks/use-keyboard-shortcuts";
    34→import { Alert, AlertDescription } from "@/components/ui/alert";
    35→
    36→const createTenderSchema = z.object({
    37→  title: z.string().min(3, "Title must be at least 3 characters"),
    38→  description: z.string().min(10, "Description must be at least 10 characters"),
    39→  deadline: z.string().min(1, "Deadline is required").refine((val) => {
    40→    const deadlineDate = new Date(val);
    41→    const now = new Date();
    42→    return deadlineDate.getTime() > now.getTime();
    43→  }, "Must be a future date"),
    44→  budget: z.string().optional(),
    45→  duration: z.string().optional(),
    46→  projectTimeline: z.string().min(3, "Project timeline is required"),
    47→  voiceNoteUrl: z.string().optional(),
    48→  videoUrl: z.string().url("Must be a valid URL").optional().or(z.literal("")),
    49→});
    50→
    51→type CreateTenderForm = z.infer<typeof createTenderSchema>;
    52→
    53→const FORM_ID = 'create-tender';
    54→const REQUIRED_FIELDS: (keyof CreateTenderForm)[] = ['title', 'description', 'deadline', 'projectTimeline'];
    55→
    56→// Animated Circle Component
    57→function AnimatedCircle() {
    58→  return (
    59→    <div className="relative w-32 h-32 mx-auto mb-8">
    60→      <style>{`
    61→        @keyframes orbitCircle {
    62→          0% {
    63→            transform: rotate(0deg);
    64→            box-shadow:
    65→              0 6px 12px 0 #FF6B4A inset,
    66→              0 12px 18px 0 #E25E45 inset,
    67→              0 0 3px 1.2px rgba(255, 107, 74, 0.4),
    68→              0 0 12px 3px rgba(226, 94, 69, 0.2);
    69→          }
    70→          50% {
    71→            transform: rotate(180deg);
    72→            box-shadow:
    73→              0 6px 12px 0 #FF8A6B inset,
    74→              0 12px 6px 0 #E25E45 inset,
    75→              0 0 3px 1.2px rgba(255, 107, 74, 0.4),
    76→              0 0 12px 3px rgba(226, 94, 69, 0.2);
    77→          }
    78→          100% {
    79→            transform: rotate(360deg);
    80→            box-shadow:
    81→              0 6px 12px 0 #FF6B4A inset,
    82→              0 12px 18px 0 #E25E45 inset,
    83→              0 0 3px 1.2px rgba(255, 107, 74, 0.4),
    84→              0 0 12px 3px rgba(226, 94, 69, 0.2);
    85→          }
    86→        }
    87→
    88→        .animate-orbit {
    89→          animation: orbitCircle 4s linear infinite;
    90→        }
    91→      `}</style>
    92→      <div className="absolute inset-0 rounded-full animate-orbit" />
    93→      <div className="absolute inset-2 rounded-full bg-gradient-to-br from-[#E25E45] to-[#d54d35] flex items-center justify-center">
    94→        <Sparkles className="w-12 h-12 text-white" />
    95→      </div>
    96→    </div>
    97→  );
    98→}
