   100→export default function CreateTender() {
   101→  const { user, activeCompany } = useAuthStore();
   102→  const { toast } = useToast();
   103→  const { language } = useI18n();
   104→  const dateLocale = language === 'ar' ? arLocale : undefined;
   105→  const queryClient = useQueryClient();
   106→  const [, navigate] = useLocation();
   107→  const [createdTender, setCreatedTender] = useState<Tender | null>(null);
   108→  const [invitationCopied, setInvitationCopied] = useState(false);
   109→  const [showForm, setShowForm] = useState(false);
   110→  const [showReview, setShowReview] = useState(false);
   111→  const [reviewData, setReviewData] = useState<CreateTenderForm | null>(null);
   112→  const [showDraftPrompt, setShowDraftPrompt] = useState(false);
   113→  const [hasDraft, setHasDraft] = useState(false);
   114→  const [showAdvanced, setShowAdvanced] = useState(false);
   115→
   116→  // Fetch tenders to check if user has created any
   117→  const { data: tenders = [] } = useQuery<Tender[]>({
   118→    queryKey: ['/api/tenders'],
   119→    enabled: !!activeCompany,
   120→  });
   121→
   122→  const form = useForm<CreateTenderForm>({
   123→    resolver: zodResolver(createTenderSchema),
   124→    mode: 'onChange',
   125→    defaultValues: {
   126→      title: "",
   127→      description: "",
   128→      deadline: "",
   129→      budget: "",
   130→      duration: "",
   131→      projectTimeline: "",
   132→      voiceNoteUrl: "",
   133→      videoUrl: "",
   134→    },
   135→  });
   136→
   137→  const formValues = form.watch();
   138→  const { lastSaved, isSaving, clearDraft, loadDraft } = useAutosave(
   139→    FORM_ID,
   140→    formValues,
   141→    showForm && !createdTender
   142→  );
   143→
   144→  const progress = calculateFormProgress(form, REQUIRED_FIELDS);
   145→
   146→  useEffect(() => {
   147→    const draft = DraftStorage.load<CreateTenderForm>(FORM_ID);
   148→    if (draft && !createdTender && showForm) {
   149→      setHasDraft(true);
   150→      setShowDraftPrompt(true);
   151→    }
   152→  }, [showForm, createdTender]);
   153→
   154→  useFormKeyboardShortcuts({
   155→    onSubmit: () => {
   156→      if (!createdTender && showForm) {
   157→        form.handleSubmit(onSubmit)();
   158→      }
   159→    },
   160→    onCancel: () => navigate('/dashboard'),
   161→    enabled: true,
   162→  });
   163→
   164→  const createTenderMutation = useMutation({
   165→    mutationFn: async (data: CreateTenderForm) => {
   166→      const response = await apiRequest('POST', '/api/tenders', data);
   167→      if (!response.ok) {
   168→        const error = await response.json();
   169→        throw error;
   170→      }
   171→      return response.json();
   172→    },
   173→    onSuccess: (tender: Tender) => {
   174→      setCreatedTender(tender);
   175→      setShowReview(false);
   176→      setReviewData(null);
   177→      clearDraft();
   178→      queryClient.invalidateQueries({ queryKey: ['/api/tenders'] });
   179→      const inviteLink = `${window.location.origin}/invite/${tender.invitationToken}`;
   180→      toast({
   181→        title: "Success!",
   182→        description: "Tender created successfully",
   183→        action: (
   184→          <ToastAction altText="Copy invitation link" onClick={() => { navigator.clipboard.writeText(inviteLink); toast({ title: "Link copied!" }); }}>
   185→            <Copy className="h-3 w-3 mr-1" /> Copy Link
   186→          </ToastAction>
   187→        ),
   188→        duration: 10000,
   189→      });
   190→    },
   191→    onError: (error: any) => {
   192→      if (error?.requiresProfile) {
   193→        toast({
   194→          title: "Profile Required",
   195→          description: "Please complete your company profile before creating tenders",
   196→        });
   197→        navigate('/company-onboarding');
   198→      } else {
   199→        toast({
   200→          title: "Error",
   201→          description: error?.message || "Failed to create tender",
   202→          variant: "destructive",
   203→        });
   204→      }
   205→    },
   206→  });
   207→
   208→  const onSubmit = (data: CreateTenderForm) => {
   209→    setReviewData(data);
   210→    setShowReview(true);
   211→  };
   212→
   213→  const handlePublishTender = () => {
   214→    if (reviewData) {
   215→      createTenderMutation.mutate(reviewData);
   216→    }
   217→  };
   218→
   219→  const handleBackToEdit = () => {
   220→    setShowReview(false);
   221→  };
   222→
   223→  const handleLoadDraft = () => {
   224→    const draft = loadDraft();
   225→    if (draft) {
   226→      form.reset(draft.data);
   227→      setShowDraftPrompt(false);
   228→      toast({
   229→        title: "Draft loaded",
   230→        description: "Your previous work has been restored",
   231→      });
   232→    }
   233→  };
   234→
   235→  const copyInvitationLink = async () => {
   236→    if (!createdTender) return;
   237→    const invitationLink = `${window.location.origin}/invite/${createdTender.id}`;
   238→    try {
   239→      await navigator.clipboard.writeText(invitationLink);
   240→      setInvitationCopied(true);
   241→      setTimeout(() => setInvitationCopied(false), 2000);
   242→      toast({
   243→        title: "Copied!",
   244→        description: "Invitation link copied to clipboard",
   245→      });
   246→    } catch (error) {
   247→      toast({
   248→        title: "Error",
   249→        description: "Failed to copy link",
   250→        variant: "destructive",
   251→      });
   252→    }
   253→  };
   254→
   255→  // Success State
   256→  if (createdTender) {
   257→    const invitationLink = `${window.location.origin}/invite/${createdTender.id}`;
   258→    
   259→    return (
   260→      <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 dark:from-gray-900 dark:to-gray-800 py-12 px-4">
   261→        <div className="max-w-2xl mx-auto">
   262→          <div className="flex items-center justify-between mb-8">
   263→            <img src={logoPath} alt="Bid" className="h-16 cursor-pointer hover:opacity-80 transition-opacity" onClick={() => navigate('/dashboard')} />
   264→            <Button 
   265→              onClick={() => navigate('/dashboard')}
   266→              className="group relative overflow-hidden"
   267→              data-testid="button-back"
   268→            >
   269→              <span className="w-20 translate-x-2 transition-opacity duration-500 group-hover:opacity-0">Back</span>
   270→              <i className="absolute inset-0 z-10 grid w-1/4 place-items-center bg-primary-foreground/15 transition-all duration-500 group-hover:w-full">
   271→                <ArrowLeft className="opacity-60" size={16} strokeWidth={2} aria-hidden="true" />
   272→              </i>
   273→            </Button>
   274→          </div>
   275→
   276→          <Card className="border-0 shadow-2xl">
   277→            <CardContent className="pt-12 pb-8">
   278→              <div className="text-center space-y-6">
   279→                <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-green-100 dark:bg-green-900/30">
   280→                  <Check className="h-10 w-10 text-green-600 dark:text-green-400" />
   281→                </div>
   282→                <div>
   283→                  <h2 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">Tender Created!</h2>
   284→                  <p className="text-xl font-semibold text-[#E25E45] mb-4">{createdTender.title}</p>
   285→                  <p className="text-gray-600 dark:text-gray-400">Your tender is now live and ready for vendor invitations</p>
   286→                </div>
   287→
   288→                <Card className="mt-8 bg-blue-50 dark:bg-blue-950/30 border-blue-200 dark:border-blue-800">
   289→                  <CardContent className="p-6">
   290→                    <div className="flex items-center gap-3 mb-4">
   291→                      <Mail className="h-5 w-5 text-blue-600 dark:text-blue-400" />
   292→                      <h4 className="font-semibold text-blue-900 dark:text-blue-100">Share Your Invitation Link</h4>
   293→                    </div>
   294→                    <p className="text-sm text-blue-800 dark:text-blue-200 mb-4">Share this with vendors to invite them to submit offers:</p>
   295→                    <div className="bg-white dark:bg-gray-900 rounded-lg p-3 mb-4 break-all">
   296→                      <code className="text-xs text-blue-900 dark:text-blue-100 font-mono">{invitationLink}</code>
   297→                    </div>
   298→                    <div className="flex gap-2">
   299→                      <Button 
   300→                        onClick={copyInvitationLink}
   301→                        size="sm"
   302→                        className="flex-1"
   303→                        data-testid="button-copy-link"
   304→                      >
   305→                        {invitationCopied ? (
   306→                          <><Check className="h-4 w-4 mr-2" />Copied!</>
   307→                        ) : (
   308→                          <><Copy className="h-4 w-4 mr-2" />Copy Link</>
   309→                        )}
   310→                      </Button>
   311→                      <Button 
   312→                        onClick={() => navigate(`/tenders/${createdTender.id}`)}
   313→                        variant="outline"
   314→                        size="sm"
   315→                        className="flex-1"
   316→                        data-testid="button-view-tender"
   317→                      >
   318→                        <ExternalLink className="h-4 w-4 mr-2" />
   319→                        View Details
   320→                      </Button>
   321→                    </div>
   322→                  </CardContent>
   323→                </Card>
   324→
   325→                <div className="flex gap-3 pt-4">
   326→                  <Button 
   327→                    variant="outline" 
   328→                    onClick={() => navigate('/dashboard')}
   329→                    className="flex-1"
   330→                    data-testid="button-back-dashboard"
   331→                  >
   332→                    <ArrowLeft className="h-4 w-4 mr-2" />
   333→                    Back to Dashboard
   334→                  </Button>
   335→                </div>
   336→              </div>
   337→            </CardContent>
   338→          </Card>
   339→        </div>
   340→      </div>
   341→    );
   342→  }
   343→
   344→  // Review/Confirmation Screen
   345→  if (showReview && reviewData) {
   346→    return (
   347→      <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 dark:from-gray-900 dark:to-gray-800 py-12 px-4">
   348→        <div className="max-w-3xl mx-auto">
   349→          <div className="flex items-center justify-between mb-8">
   350→            <img src={logoPath} alt="Bid" className="h-16 cursor-pointer hover:opacity-80 transition-opacity" onClick={() => navigate('/dashboard')} />
   351→            <Button 
   352→              onClick={handleBackToEdit}
   353→              className="group relative overflow-hidden"
   354→              data-testid="button-back-to-edit"
   355→            >
   356→              <span className="w-20 translate-x-2 transition-opacity duration-500 group-hover:opacity-0">Edit</span>
   357→              <i className="absolute inset-0 z-10 grid w-1/4 place-items-center bg-primary-foreground/15 transition-all duration-500 group-hover:w-full">
   358→                <ArrowLeft className="opacity-60" size={16} strokeWidth={2} aria-hidden="true" />
   359→              </i>
   360→            </Button>
   361→          </div>
   362→
   363→          <Card className="border-0 shadow-2xl overflow-hidden">
   364→            <div className="h-1 bg-gradient-to-r from-[#E25E45] to-[#FF8A6B]" />
   365→            
   366→            <CardHeader className="pb-4">
   367→              <div className="flex items-center gap-4">
   368→                <div className="h-12 w-12 rounded-full bg-gradient-to-br from-[#E25E45] to-[#d54d35] flex items-center justify-center">
   369→                  <Check className="h-6 w-6 text-white" />
   370→                </div>
   371→                <div>
   372→                  <CardTitle className="text-2xl font-bold">Review Your Tender</CardTitle>
   373→                  <CardDescription>Please confirm the details before publishing</CardDescription>
   374→                </div>
   375→              </div>
   376→            </CardHeader>
   377→
   378→            <CardContent className="space-y-6">
   379→              {/* Tender Brief */}
   380→              <div className="space-y-4">
   381→                <div className="p-4 bg-gray-50 dark:bg-gray-800/50 rounded-lg border border-gray-200 dark:border-gray-700">
   382→                  <h3 className="text-sm font-semibold text-gray-500 dark:text-gray-400 mb-1">Project Title</h3>
   383→                  <p className="text-lg font-bold text-gray-900 dark:text-white" data-testid="review-title">{reviewData.title}</p>
   384→                </div>
   385→
   386→                <div className="p-4 bg-gray-50 dark:bg-gray-800/50 rounded-lg border border-gray-200 dark:border-gray-700">
   387→                  <h3 className="text-sm font-semibold text-gray-500 dark:text-gray-400 mb-1">Description</h3>
   388→                  <p className="text-gray-900 dark:text-white whitespace-pre-wrap" data-testid="review-description">{reviewData.description}</p>
   389→                </div>
   390→
   391→                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
   392→                  <div className="p-4 bg-gray-50 dark:bg-gray-800/50 rounded-lg border border-gray-200 dark:border-gray-700">
   393→                    <h3 className="text-sm font-semibold text-gray-500 dark:text-gray-400 mb-1">Deadline</h3>
   394→                    <p className="text-gray-900 dark:text-white font-medium flex items-center gap-2" data-testid="review-deadline">
   395→                      <CalendarIcon className="h-4 w-4 text-[#E25E45]" />
   396→                      {reviewData.deadline ? format(new Date(reviewData.deadline), "PPP 'at' HH:mm", { locale: dateLocale }) : "Not specified"}
   397→                    </p>
   398→                  </div>
   399→
   400→                  <div className="p-4 bg-gray-50 dark:bg-gray-800/50 rounded-lg border border-gray-200 dark:border-gray-700">
   401→                    <h3 className="text-sm font-semibold text-gray-500 dark:text-gray-400 mb-1">Budget Range</h3>
   402→                    <p className="text-gray-900 dark:text-white font-medium" data-testid="review-budget">
   403→                      {reviewData.budget || "Not specified"}
   404→                    </p>
   405→                  </div>
   406→
   407→                  <div className="p-4 bg-gray-50 dark:bg-gray-800/50 rounded-lg border border-gray-200 dark:border-gray-700">
   408→                    <h3 className="text-sm font-semibold text-gray-500 dark:text-gray-400 mb-1">Project Timeline</h3>
   409→                    <p className="text-gray-900 dark:text-white font-medium" data-testid="review-timeline">
   410→                      {reviewData.projectTimeline}
   411→                    </p>
   412→                  </div>
   413→
   414→                  {(reviewData.voiceNoteUrl || reviewData.videoUrl) && (
   415→                    <div className="p-4 bg-gray-50 dark:bg-gray-800/50 rounded-lg border border-gray-200 dark:border-gray-700">
   416→                      <h3 className="text-sm font-semibold text-gray-500 dark:text-gray-400 mb-1">Attachments</h3>
   417→                      <div className="flex flex-wrap gap-2">
   418→                        {reviewData.voiceNoteUrl && (
   419→                          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-[#E25E45]/10 text-[#E25E45]">
   420→                            <Sparkles className="h-3 w-3 mr-1" />
   421→                            Voice Note
   422→                          </span>
   423→                        )}
   424→                        {reviewData.videoUrl && (
   425→                          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400">
   426→                            <Video className="h-3 w-3 mr-1" />
   427→                            Video Link
   428→                          </span>
   429→                        )}
   430→                      </div>
   431→                    </div>
   432→                  )}
   433→                </div>
   434→              </div>
   435→
   436→              {/* Company Info */}
   437→              {activeCompany && (
   438→                <Alert className="bg-blue-50 dark:bg-blue-950/30 border-blue-200 dark:border-blue-800">
   439→                  <Info className="h-4 w-4 text-blue-600" />
   440→                  <AlertDescription className="text-blue-900 dark:text-blue-100">
   441→                    This tender will be published on behalf of <strong>{activeCompany.name}</strong>
   442→                  </AlertDescription>
   443→                </Alert>
   444→              )}
   445→
   446→              {/* Actions */}
   447→              <div className="flex gap-3 pt-6 border-t border-gray-200 dark:border-gray-700">
   448→                <Button 
   449→                  variant="outline" 
   450→                  onClick={handleBackToEdit}
   451→                  className="flex-1"
   452→                  data-testid="button-back-edit"
   453→                >
   454→                  <ArrowLeft className="h-4 w-4 mr-2" />
   455→                  Go Back & Edit
   456→                </Button>
   457→                <Button 
   458→                  onClick={handlePublishTender}
   459→                  className="flex-1 bg-[#E25E45] hover:bg-[#d54d35]"
   460→                  disabled={createTenderMutation.isPending}
   461→                  data-testid="button-publish-tender"
   462→                >
   463→                  {createTenderMutation.isPending ? (
   464→                    <>Publishing...</>
   465→                  ) : (
   466→                    <>
   467→                      <Check className="h-4 w-4 mr-2" />
   468→                      Publish Tender
   469→                    </>
   470→                  )}
   471→                </Button>
   472→              </div>
   473→            </CardContent>
   474→          </Card>
   475→        </div>
   476→      </div>
   477→    );
   478→  }
   479→
   480→  // Welcome Screen
   481→  if (!showForm) {
   482→    return (
   483→      <div className="relative min-h-screen bg-white dark:bg-neutral-950 overflow-hidden flex items-center justify-center p-4">
   484→        <FlickeringGrid 
   485→          className="absolute inset-0"
   486→          squareSize={4}
   487→          gridGap={6}
   488→          flickerChance={0.3}
   489→          maxOpacity={0.08}
   490→          color={`rgb(${226}, ${94}, ${69})`}
   491→        />
   492→        <div className="relative z-10 max-w-md">
   493→          <div className="text-center space-y-8">
   494→            <img src={logoPath} alt="Bid" className="h-40 mx-auto cursor-pointer hover:opacity-80 transition-opacity" onClick={() => navigate('/dashboard')} />
   495→            
   496→            <AnimatedCircle />
