    95→
    96→  const savingsMutation = useMutation({
    97→    mutationFn: async (data: any) => {
    98→      const response = await apiRequest("POST", `/api/tenders/${tenderId}/savings`, data);
    99→      return response.json();
   100→    },
   101→    onSuccess: (data) => {
