   141→  const cheapestId = totals.length > 0 ? totals.reduce((min, t) => t.total < min.total ? t : min, totals[0]).id : null;
   142→  const mostExpensiveId = totals.length > 0 ? totals.reduce((max, t) => t.total > max.total ? t : max, totals[0]).id : null;
   143→  const highestPrice = totals.length > 0 ? Math.max(...totals.map(t => t.total)) : 0;
   144→  const lowestPrice = totals.length > 0 ? Math.min(...totals.map(t => t.total)) : 0;
