    86→function AudioPlayer({ src }: { src: string }) {
    87→  const audioRef = useRef<HTMLAudioElement>(null);
    88→  const [isPlaying, setIsPlaying] = useState(false);
    89→  const [isLoading, setIsLoading] = useState(true);
    90→  const [audioUrl, setAudioUrl] = useState<string | null>(null);
    91→  const [currentTime, setCurrentTime] = useState(0);
    92→  const [duration, setDuration] = useState(0);
    93→  const [error, setError] = useState<string | null>(null);
    94→
    95→  useEffect(() => {
    96→    const loadAudio = async () => {
    97→      setIsLoading(true);
    98→      setError(null);
    99→      try {
   100→        const token = localStorage.getItem("token");
   101→        const response = await fetch(src, {
   102→          headers: { Authorization: `Bearer ${token}` }
   103→        });
   104→        if (!response.ok) throw new Error("Failed to load audio");
   105→        const blob = await response.blob();
   106→        const url = URL.createObjectURL(blob);
   107→        setAudioUrl(url);
   108→      } catch (err) {
   109→        setError("Failed to load voice note");
   110→        console.error(err);
   111→      } finally {
   112→        setIsLoading(false);
   113→      }
   114→    };
   115→    loadAudio();
   116→    return () => {
   117→      if (audioUrl) URL.revokeObjectURL(audioUrl);
   118→    };
   119→  }, [src]);
   120→
   121→  const togglePlay = () => {
   122→    if (!audioRef.current) return;
   123→    if (isPlaying) {
   124→      audioRef.current.pause();
   125→    } else {
   126→      audioRef.current.play();
   127→    }
   128→    setIsPlaying(!isPlaying);
   129→  };
   130→
   131→  const formatTime = (time: number) => {
   132→    if (!isFinite(time) || isNaN(time)) return '00:00';
   133→    const mins = Math.floor(time / 60);
   134→    const secs = Math.floor(time % 60);
   135→    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
   136→  };
   137→
   138→  if (isLoading) {
   139→    return (
   140→      <div className="flex items-center gap-2 p-3 bg-gray-100 dark:bg-gray-800 rounded-lg">
   141→        <Loader2 className="h-5 w-5 animate-spin" />
   142→        <span className="text-sm text-muted-foreground">Loading voice note...</span>
   143→      </div>
   144→    );
   145→  }
   146→
   147→  if (error || !audioUrl) {
   148→    return (
   149→      <div className="flex items-center gap-2 p-3 bg-red-50 dark:bg-red-900/20 rounded-lg text-red-600">
   150→        <AlertCircle className="h-5 w-5" />
   151→        <span className="text-sm">{error || "Failed to load voice note"}</span>
   152→      </div>
   153→    );
   154→  }
   155→
   156→  const progress = duration > 0 ? (currentTime / duration) * 100 : 0;
   157→
   158→  return (
   159→    <div className="flex items-center gap-3 p-3 bg-gray-100 dark:bg-gray-800 rounded-lg" data-testid="audio-player">
   160→      <Button
   161→        variant="ghost"
   162→        size="icon"
   163→        onClick={togglePlay}
   164→        className="h-10 w-10 rounded-full bg-[#E25E45] text-white hover:bg-[#d54d35]"
   165→        data-testid="button-audio-play"
   166→      >
   167→        {isPlaying ? <Pause className="h-5 w-5" /> : <Play className="h-5 w-5 ml-0.5" />}
   168→      </Button>
   169→      <div className="flex-1">
   170→        <div
   171→          className="relative h-2 bg-gray-300 dark:bg-gray-600 rounded-full cursor-pointer"
   172→          onClick={(e) => {
   173→            if (!audioRef.current || !duration || !isFinite(duration)) return;
   174→            const rect = e.currentTarget.getBoundingClientRect();
   175→            const clickX = e.clientX - rect.left;
   176→            const newTime = (clickX / rect.width) * duration;
   177→            if (!isFinite(newTime) || isNaN(newTime)) return;
   178→            audioRef.current.currentTime = Math.max(0, Math.min(newTime, duration));
   179→            setCurrentTime(Math.max(0, Math.min(newTime, duration)));
   180→          }}
   181→        >
   182→          <div
   183→            className="absolute top-0 left-0 h-full bg-[#E25E45] rounded-full"
   184→            style={{
   185→              width: `${progress}%`,
   186→              transition: isPlaying ? 'width 0.1s linear' : 'none'
   187→            }}
   188→          />
   189→          <div
   190→            className="absolute top-1/2 -translate-y-1/2 h-4 w-4 bg-[#E25E45] rounded-full shadow-md border-2 border-white"
   191→            style={{
   192→              left: `calc(${progress}% - 8px)`,
   193→              transition: isPlaying ? 'left 0.1s linear' : 'none'
   194→            }}
   195→          />
   196→        </div>
   197→        <div className="flex justify-between text-xs text-muted-foreground mt-2">
   198→          <span>{formatTime(currentTime)}</span>
   199→          <span>{formatTime(duration)}</span>
   200→        </div>
   201→      </div>
   202→      <audio
   203→        ref={audioRef}
   204→        src={audioUrl}
   205→        preload="metadata"
   206→        onTimeUpdate={() => setCurrentTime(audioRef.current?.currentTime || 0)}
   207→        onLoadedMetadata={() => setDuration(audioRef.current?.duration || 0)}
   208→        onEnded={() => {
   209→          setIsPlaying(false);
   210→          setCurrentTime(0);
   211→        }}
   212→      />
   213→    </div>
   214→  );
   215→}
